  "inlineSchema": "// Schema de Prisma: define cómo es la base de datos\n// Prisma lo lee y crea las tablas automáticamente\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// PostgreSQL: base de datos en la nube (Supabase)\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// Tabla de restaurantes (3 sucursales en el demo)\nmodel Restaurant {\n  id            String @id @default(uuid())\n  name          String\n  // Cuántos puntos vale cada peso: 1.0 = 1 punto por $1 (ahora sumaremos fijo 1 pt por pedido, pero dejamos esto por si acaso)\n  pointsPerPeso Float  @default(1.0)\n\n  // Medios de pago aceptados por esta sucursal\n  acceptsCash        Boolean @default(true)\n  acceptsTransfer    Boolean @default(true)\n  acceptsMercadoPago Boolean @default(true)\n\n  createdAt DateTime @default(now())\n\n  // Relaciones: un restaurante tiene muchos clientes, pedidos y productos\n  customers Customer[]\n  orders    Order[]\n  products  Product[]\n}\n\n// Nueva tabla de Productos (Catálogo)\nmodel Product {\n  id          String   @id @default(uuid())\n  name        String\n  description String?\n  price       Float\n  imageUrl    String?\n  createdAt   DateTime @default(now())\n\n  // Relaciones\n  restaurant   Restaurant           @relation(fields: [restaurantId], references: [id])\n  restaurantId String\n  orderItems   OrderItem[]\n  optionGroups ProductOptionGroup[]\n}\n\n// Grupo de Opciones (ej: \"Bebida\", \"Agregados\")\nmodel ProductOptionGroup {\n  id            String  @id @default(uuid())\n  name          String\n  isRequired    Boolean @default(false)\n  maxSelections Int     @default(1)\n\n  product   Product               @relation(fields: [productId], references: [id], onDelete: Cascade)\n  productId String\n  choices   ProductOptionChoice[]\n}\n\n// Opciones Individuales (ej: \"Coca Cola +$500\")\nmodel ProductOptionChoice {\n  id              String @id @default(uuid())\n  name            String\n  additionalPrice Float  @default(0)\n\n  group   ProductOptionGroup @relation(fields: [groupId], references: [id], onDelete: Cascade)\n  groupId String\n}\n\n// Tabla de clientes del restaurante\nmodel Customer {\n  id          String   @id @default(uuid())\n  name        String\n  phone       String // Teléfono único para identificar al cliente\n  totalPoints Int      @default(0) // Puntos acumulados totales\n  createdAt   DateTime @default(now())\n\n  // Relaciones\n  restaurant   Restaurant @relation(fields: [restaurantId], references: [id])\n  restaurantId String\n  orders       Order[]\n\n  // No puede haber dos clientes con el mismo teléfono en el mismo restaurante\n  @@unique([phone, restaurantId])\n}\n\n// Tabla de pedidos adaptada al carrito\nmodel Order {\n  id           String   @id @default(uuid())\n  amount       Float // Monto total en pesos\n  pointsEarned Int // Puntos ganados en este pedido (1 punto ahora)\n  orderType    String   @default(\"delivery\") // delivery, pickup, mesa\n  // Token único que iba en el QR, lo dejamos por retrocompatibilidad\n  qrToken      String   @unique @default(uuid())\n  // \"pending\" = nuevo, \"preparing\", \"ready\", \"delivered\"\n  status       String   @default(\"pending\")\n  createdAt    DateTime @default(now())\n\n  // Relaciones\n  customer     Customer    @relation(fields: [customerId], references: [id])\n  customerId   String\n  restaurant   Restaurant  @relation(fields: [restaurantId], references: [id])\n  restaurantId String\n  items        OrderItem[]\n}\n\n// Item individual dentro de un Pedido (el carrito del cliente)\nmodel OrderItem {\n  id              String  @id @default(uuid())\n  quantity        Int\n  price           Float // Precio base + opciones al momento de la compra\n  selectedOptions String? // JSON o texto de las opciones elegidas para rápido acceso (\"+ Coca, + Cheddar\")\n\n  // Relaciones\n  order     Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  orderId   String\n  product   Product @relation(fields: [productId], references: [id])\n  productId String\n}\n",
